import json
import pickle

def lambda_handler(event, context):
    # Deserialize the JSON event payload
    data = json.loads(event['body'])
    
    # Process the deserialized data (example processing)
    processed_data = process_user_actions(data)
    
    # Serialize the processed data using pickle for fast serialization
    serialized_data = pickle.dumps(processed_data)
    
    return {
        'statusCode': 200,
        'headers': {
            'Content-Type': 'application/octet-stream',
        },
        'body': serialized_data,
    }

def process_user_actions(data):
    # Example processing function (modify as needed)
    processed = []
    for action in data['actions']:
        if action['type'] == 'update':
            processed.append(f"Processed update: {action['details']}")
        elif action['type'] == 'delete':
            processed.append(f"Processed delete: {action['details']}")
    return processed